import { WEBUI_API_BASE_URL } from '$lib/constants';

const GPTHUB_API_BASE_URL = `${WEBUI_API_BASE_URL}/gpthub`;

const parseDownloadFilename = (contentDisposition: string | null, fallback: string): string => {
	if (!contentDisposition) return fallback;
	const utf8Match = contentDisposition.match(/filename\\*=UTF-8''([^;]+)/i);
	if (utf8Match?.[1]) {
		try {
			return decodeURIComponent(utf8Match[1]);
		} catch {
			return utf8Match[1];
		}
	}
	const plainMatch = contentDisposition.match(/filename=\"?([^\";]+)\"?/i);
	if (plainMatch?.[1]) return plainMatch[1];
	return fallback;
};

export const getGPTHubConfig = async (token: string) => {
	let error = null;
	const res = await fetch(`${GPTHUB_API_BASE_URL}/config`, {
		method: 'GET',
		headers: {
			'Content-Type': 'application/json',
			Authorization: `Bearer ${token}`
		}
	})
		.then(async (r) => {
			if (!r.ok) throw await r.json();
			return r.json();
		})
		.catch((err) => {
			error = err?.detail ?? 'Failed to load GPTHub config';
			return null;
		});
	if (error) throw error;
	return res;
};

