export const downloadWorkspaceArchive = async (
	token: string,
	ownerId: string,
	workspaceId: string
): Promise<{ blob: Blob; filename: string }> => {
	let error = null;
	const res = await fetch(`${GPTHUB_API_BASE_URL}/workspaces/${ownerId}/${workspaceId}/download`, {
		method: 'GET',
		headers: { Authorization: `Bearer ${token}` }
	})
		.then(async (r) => {
			if (!r.ok) throw await r.json();
			const blob = await r.blob();
			const filename = parseDownloadFilename(
				r.headers.get('Content-Disposition'),
				`workspace_${workspaceId.slice(0, 8)}.zip`
			);
			return { blob, filename };
		})
		.catch((err) => {
			error = err?.detail ?? 'Failed to download workspace';
			return null;
		});
	if (error) throw error;
	return res as { blob: Blob; filename: string };
};

