export type MediaGalleryKind = 'upload' | 'generated';

export type MediaGalleryItem = {
	id: string;
	owner_id: string;
	kind: MediaGalleryKind;
	media_url: string;
	thumbnail_url: string | null;
	chat_id: string | null;
	message_id: string | null;
	thread_id: string | null;
	prompt_text: string;
	model_id: string;
	provider: string;
	width: number | null;
	height: number | null;
	mime_type: string;
	size_bytes: number | null;
	source_ref: string;
	created_at: string;
	updated_at: string;
};

export type MediaGalleryListResponse = {
	items: MediaGalleryItem[];
	total: number;
	page: number;
	page_size: number;
};

export const listMediaGalleryItems = async (
	token: string,
	ownerId: string,
	params?: {
		page?: number;
		page_size?: number;
		kind?: MediaGalleryKind;
		search?: string;
		model_id?: string;
		chat_id?: string;
		thread_id?: string;
		date_from?: string;
		date_to?: string;
	}
): Promise<MediaGalleryListResponse> => {
	let error = null;
	const query = new URLSearchParams();
	if (params?.page) query.set('page', String(params.page));
	if (params?.page_size) query.set('page_size', String(params.page_size));
	if (params?.kind) query.set('kind', params.kind);
	if (params?.search) query.set('search', params.search);
	if (params?.model_id) query.set('model_id', params.model_id);
	if (params?.chat_id) query.set('chat_id', params.chat_id);
	if (params?.thread_id) query.set('thread_id', params.thread_id);
	if (params?.date_from) query.set('date_from', params.date_from);
	if (params?.date_to) query.set('date_to', params.date_to);
	const qs = query.toString();
	const url = `${GPTHUB_API_BASE_URL}/media-gallery/${ownerId}${qs ? `?${qs}` : ''}`;

	const res = await fetch(url, {
		method: 'GET',
		headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` }
	})
		.then(async (r) => {
			if (!r.ok) throw await r.json();
			return r.json();
		})
		.catch((err) => {
			error = err?.detail ?? 'Failed to list media gallery items';
			return null;
		});
	if (error) throw error;
	return (
		res ?? {
			items: [],
			total: 0,
			page: params?.page ?? 1,
			page_size: params?.page_size ?? 24
		}
	);
};

